}

parameters.amount:
={{ 
  const followUpDate = new Date($('Webhook — Prescription Received').item.json.follow_up_date);
  const reminderDate = new Date(followUpDate);
  reminderDate.setDate(reminderDate.getDate() - 2);
  reminderDate.setHours(9, 0, 0, 0);
  const now = new Date();
  const diff = Math.max(0, reminderDate - now);
  return Math.floor(diff / 1000);
}}

